import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as e,d as n}from"./app-75fed8c6.js";const a={},u=n('<h2 id="linux" tabindex="-1"><a class="header-anchor" href="#linux" aria-hidden="true">#</a> Linux</h2><ul><li>linux 是一套免费使用和自由传播到类 Unix 操作系统</li><li>在服务器端领域和嵌入式领域有非常广泛的应用</li></ul><h2 id="版本" tabindex="-1"><a class="header-anchor" href="#版本" aria-hidden="true">#</a> 版本</h2><p>分为内核版本和发型版本</p><ul><li>kemei</li><li>各个厂商惠制作自己的发型版本 <ul><li>redhat</li><li>CentOS</li><li>ubuntu</li><li>fedora</li></ul></li></ul><h2 id="linux-与-windows-的不同" tabindex="-1"><a class="header-anchor" href="#linux-与-windows-的不同" aria-hidden="true">#</a> Linux 与 Windows 的不同</h2><ul><li>Linux 严格区分大小写</li><li>Linux 中所有内容以文件形式保存，包括硬件、用户和文件</li><li>Linux 不靠扩展名区分文件类型，是靠权限来区分，但是有一些约定的扩展名，是给管理员看的 <ul><li>压缩包 .gz .bz2 .tar .tgz</li><li>二进制文件 .rpm</li><li>网页文件 .html .php</li><li>脚本文件 .sh</li><li>配置文件 .conf</li></ul></li><li>Windows 下的程序不能直接在 Linux 中安装和运行</li><li>Linux 更多实用字符界面 <ul><li>占用的系统资源更少</li><li>减少了出错和被攻击的可能行，会让系统更稳定</li></ul></li></ul>',7),r=[u];function t(d,h){return l(),e("div",null,r)}const c=i(a,[["render",t],["__file","01.介绍.html.vue"]]);export{c as default};
